-- Migration: importar Vendas GERAL -> propostas (FK contact_id por CPF)
-- Insere apenas propostas com cliente identificado. Backup: propostas_backup_20260708.

drop table if exists stg_vendas;
create table stg_vendas (cpf_n text, nome text, produto text, operacao text, bco_op text, bco_port text, status text, sub_status text, saldo text, cms_pct text, comissao text, parcela text, parcela_reduzida text, qtde_parc text, taxa text, num_proposta text, num_contrato text, data_cip_averb text, promotora text);

-- garantir coluna para a parcela reduzida
alter table propostas add column if not exists parcela_reduzida numeric;

-- backup (idempotente)
create table if not exists propostas_backup_20260708 as select * from propostas;

-- inserir SOMENTE propostas com cliente identificado (match por CPF)
  saldo, cms_pct, comissao, parcela, parcela_reduzida, qtde_parc, taxa, num_proposta, num_contrato,
  data_cip_averb, promotora, created_at, updated_at)
select 1,
  (select min(c.id) from contacts c where regexp_replace(coalesce(c.cpf,''),'\D','','g')=s.cpf_n),
  s.produto, s.operacao, s.bco_op, s.bco_port, s.status, s.sub_status,
  nullif(s.saldo,'')::numeric, nullif(s.cms_pct,'')::numeric, nullif(s.comissao,'')::numeric,
  nullif(s.parcela,'')::numeric, nullif(s.parcela_reduzida,'')::numeric, nullif(s.qtde_parc,'')::int,
  nullif(s.taxa,'')::numeric, s.num_proposta, s.num_contrato, nullif(s.data_cip_averb,'')::date,
  s.promotora, now(), now()
from stg_vendas s
where exists (select 1 from contacts c where s.cpf_n is not null
              and regexp_replace(coalesce(c.cpf,''),'\D','','g')=s.cpf_n);

-- relatorio
select
 (select count(*) from propostas) as total_propostas,
 (select count(*) from propostas where contact_id is not null) as com_cliente,
 (select round(coalesce(sum(comissao),0),2) from propostas where lower(coalesce(status,'')) like 'pag%') as comissao_paga,
 (select count(*) from stg_vendas s where not exists (select 1 from contacts c where s.cpf_n is not null
    and regexp_replace(coalesce(c.cpf,''),'\D','','g')=s.cpf_n)) as puladas_sem_cliente;

-- lista das puladas (sem cliente) para conferencia
select nome, cpf_n as cpf, produto, status from stg_vendas s
where not exists (select 1 from contacts c where s.cpf_n is not null
   and regexp_replace(coalesce(c.cpf,''),'\D','','g')=s.cpf_n);
-- limpeza: drop table stg_vendas;
